import { Blob } from '@google/genai';

export function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function arrayBufferToBase64(buffer: ArrayBuffer): string {
  let binary = '';
  const bytes = new Uint8Array(buffer);
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function pcmToWav(pcmData: Float32Array, sampleRate: number): ArrayBuffer {
  const numChannels = 1;
  const byteRate = sampleRate * numChannels * 2;
  const blockAlign = numChannels * 2;
  const dataSize = pcmData.length * 2;
  const buffer = new ArrayBuffer(44 + dataSize);
  const view = new DataView(buffer);

  // RIFF chunk
  writeString(view, 0, 'RIFF');
  view.setUint32(4, 36 + dataSize, true);
  writeString(view, 8, 'WAVE');

  // fmt sub-chunk
  writeString(view, 12, 'fmt ');
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true); // PCM
  view.setUint16(22, numChannels, true);
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, byteRate, true);
  view.setUint16(32, blockAlign, true);
  view.setUint16(34, 16, true); // Bits per sample

  // data sub-chunk
  writeString(view, 36, 'data');
  view.setUint32(40, dataSize, true);

  // Write PCM samples
  let offset = 44;
  for (let i = 0; i < pcmData.length; i++) {
    const s = Math.max(-1, Math.min(1, pcmData[i]));
    view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
    offset += 2;
  }

  return buffer;
}

function writeString(view: DataView, offset: number, string: string) {
  for (let i = 0; i < string.length; i++) {
    view.setUint8(offset + i, string.charCodeAt(i));
  }
}

// For Live API Input
export function createPcmBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: arrayBufferToBase64(int16.buffer),
    mimeType: 'audio/pcm;rate=16000',
  };
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import { GoogleGenAI, Modality, Type, FunctionDeclaration } from "@google/genai";
import { base64ToUint8Array, decodeAudioData } from "../utils/audioUtils";

const apiKey = process.env.API_KEY || '';

// For features requiring user-selected keys (Veo/Pro Image)
const getClientWithUserKey = async () => {
  // @ts-ignore
  if (window.aistudio && await window.aistudio.hasSelectedApiKey()) {
     // The SDK automatically picks up the key from the environment/context in this mode
     return new GoogleGenAI({ apiKey: 'ignored-in-this-context' }); 
  }
  // Fallback or error if not selected, but we usually check before calling this
  return new GoogleGenAI({ apiKey }); 
};

const getClient = () => new GoogleGenAI({ apiKey });

// 1. Analyze Artifact (Vision)
export const analyzeArtifact = async (base64Image: string, mimeType: string) => {
  const ai = getClient();
  const model = "gemini-3-pro-preview";

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { mimeType, data: base64Image } },
        { text: "Identify the symbols, patterns, or text in this image. If it is a Swahili Leso, translate the saying. If it is Adinkra, explain the symbol's meaning and cultural origin. Provide a detailed cultural interpretation." }
      ]
    }
  });
  return response.text;
};

// 2. Knowledge Base Search (Grounding)
export const searchCulturalKnowledge = async (query: string) => {
  const ai = getClient();
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: query,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  return {
    text: response.text,
    groundingMetadata: response.candidates?.[0]?.groundingMetadata
  };
};

// 3. Storytelling (Text Generation)
export const generateStory = async (topic: string) => {
  const ai = getClient();
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: `Create a short, culturally rich story or poem about: ${topic}. Incorporate elements of Swahili or Akan folklore.`,
    config: {
      maxOutputTokens: 800,
    }
  });
  return response.text;
};

// 4. TTS (Speech Generation)
export const generateSpeech = async (text: string): Promise<AudioBuffer> => {
  const ai = getClient();
  const model = "gemini-2.5-flash-preview-tts";

  const response = await ai.models.generateContent({
    model,
    contents: [{ parts: [{ text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' }, // Kore, Puck, Charon, Fenrir, Zephyr
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio generated");

  const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  return await decodeAudioData(
    base64ToUint8Array(base64Audio),
    outputAudioContext,
    24000,
    1
  );
};

// 5. Transcribe Audio
export const transcribeAudio = async (audioBase64: string, mimeType: string) => {
  const ai = getClient();
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { mimeType, data: audioBase64 } },
        { text: "Transcribe this audio. If it contains Swahili or other African languages, detect and translate the gist into English as well." }
      ]
    }
  });
  return response.text;
};

// 6. Image Generation (Pro Image - High Quality)
export const generateDesign = async (prompt: string, size: '1K' | '2K' | '4K') => {
  // Use client with user selected key
  const ai = await getClientWithUserKey();
  const model = "gemini-3-pro-image-preview";

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [{ text: `A traditional African textile design. ${prompt}` }]
    },
    config: {
      imageConfig: {
        imageSize: size,
        aspectRatio: "1:1"
      }
    }
  });

  // Extract images
  const images: string[] = [];
  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        images.push(`data:${part.inlineData.mimeType};base64,${part.inlineData.data}`);
      }
    }
  }
  return images;
};

// 7. Image Editing (Flash Image)
export const editDesign = async (imageBase64: string, mimeType: string, prompt: string) => {
  const ai = getClient();
  const model = "gemini-2.5-flash-image"; // Nano Banana

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { mimeType, data: imageBase64 } },
        { text: prompt }
      ]
    }
  });

  const images: string[] = [];
  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        images.push(`data:${part.inlineData.mimeType};base64,${part.inlineData.data}`);
      }
    }
  }
  return images;
};

// 8. Live API Connection helper
export const getLiveClient = () => {
    return new GoogleGenAI({ apiKey });
}

