import React, { useState } from 'react';
import { analyzeArtifact } from '../services/geminiService';

const ImageAnalyzer: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<string>('');
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setAnalysis('');
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAnalyze = async () => {
    if (!image) return;
    setLoading(true);
    try {
      // Extract base64 and mime type
      const [mimePrefix, base64Data] = image.split(',');
      const mimeType = mimePrefix.match(/:(.*?);/)?.[1] || 'image/jpeg';

      const result = await analyzeArtifact(base64Data, mimeType);
      setAnalysis(result || "No analysis could be generated.");
    } catch (error) {
      console.error(error);
      setAnalysis("Error analyzing the artifact. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <h2 className="text-3xl font-bold text-amber-800 mb-2">Artifact Analyzer</h2>
      <p className="text-stone-600 mb-8">Upload an image of a Leso, Adinkra cloth, or artifact to decode its meaning.</p>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-xl shadow-md border border-stone-200">
          <label className="block w-full h-64 border-2 border-dashed border-stone-300 rounded-lg flex flex-col items-center justify-center cursor-pointer hover:bg-stone-50 hover:border-amber-400 transition-colors">
            {image ? (
              <img src={image} alt="Artifact" className="h-full w-full object-contain rounded-lg" />
            ) : (
              <div className="text-center p-4">
                <span className="text-4xl block mb-2">📸</span>
                <span className="text-stone-500 font-medium">Click to upload image</span>
              </div>
            )}
            <input type="file" className="hidden" accept="image/*" onChange={handleFileChange} />
          </label>

          <button
            onClick={handleAnalyze}
            disabled={!image || loading}
            className={`w-full mt-4 py-3 rounded-lg font-bold text-white transition-all ${
              !image || loading
                ? 'bg-stone-400 cursor-not-allowed'
                : 'bg-amber-600 hover:bg-amber-700 shadow-lg'
            }`}
          >
            {loading ? 'Consulting the Ancestors...' : 'Analyze Artifact'}
          </button>
        </div>

        <div className="bg-stone-100 p-6 rounded-xl shadow-inner border border-stone-200 h-full overflow-y-auto min-h-[300px]">
          <h3 className="text-lg font-bold text-stone-700 mb-4 border-b pb-2 border-stone-300">Wisdom Revealed</h3>
          {analysis ? (
            <div className="prose prose-stone text-stone-800 whitespace-pre-wrap">
              {analysis}
            </div>
          ) : (
            <p className="text-stone-400 italic">The analysis will appear here after processing.</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default ImageAnalyzer;

import React, { useState } from 'react';
import { generateStory, generateSpeech } from '../services/geminiService';

const Storyteller: React.FC = () => {
  const [topic, setTopic] = useState('');
  const [story, setStory] = useState('');
  const [loading, setLoading] = useState(false);
  const [audioLoading, setAudioLoading] = useState(false);

  const handleGenerate = async () => {
    if (!topic.trim()) return;
    setLoading(true);
    setStory('');
    try {
      const result = await generateStory(topic);
      setStory(result || "The spirits were silent this time.");
    } catch (error) {
      console.error(error);
      setStory("Error retrieving the story.");
    } finally {
      setLoading(false);
    }
  };

  const handleSpeak = async () => {
    if (!story) return;
    setAudioLoading(true);
    try {
      const audioBuffer = await generateSpeech(story.slice(0, 1000)); // Limit length for demo

      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start(0);
    } catch (error) {
      console.error(error);
      alert("Could not generate speech. Please try again.");
    } finally {
      setAudioLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <h2 className="text-3xl font-bold text-amber-800 mb-2">The Storyteller</h2>
      <p className="text-stone-600 mb-8">Invoke the oral traditions. Provide a symbol or theme, and receive a story.</p>

      <div className="bg-white p-6 rounded-xl shadow-lg border border-amber-100 mb-8">
        <div className="flex gap-4">
          <input
            type="text"
            value={topic}
            onChange={(e) => setTopic(e.target.value)}
            placeholder="e.g., The meaning of Sankofa, The Clever Tortoise..."
            className="flex-1 p-3 border border-stone-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-amber-500"
          />
          <button
            onClick={handleGenerate}
            disabled={loading || !topic}
            className="px-6 py-3 bg-amber-600 text-white font-bold rounded-lg hover:bg-amber-700 disabled:opacity-50 transition-colors"
          >
            {loading ? 'Weaving...' : 'Tell Story'}
          </button>
        </div>
      </div>

      {story && (
        <div className="bg-orange-50 p-8 rounded-xl border border-orange-200 shadow-sm relative">
          <button 
            onClick={handleSpeak}
            disabled={audioLoading}
            className="absolute top-4 right-4 bg-amber-800 text-white p-2 rounded-full hover:bg-amber-900 disabled:opacity-50 transition-colors"
            title="Listen to Story"
          >
            {audioLoading ? '⏳' : '🔊'}
          </button>
          <div className="prose prose-lg text-stone-800 font-serif leading-relaxed whitespace-pre-wrap">
            {story}
          </div>
        </div>
      )}
    </div>
  );
};

export default Storyteller;

import React, { useRef, useState, useEffect } from 'react';
import { getLiveClient } from '../services/geminiService';
import { createPcmBlob, decodeAudioData } from '../utils/audioUtils';
import { LiveServerMessage, Modality } from '@google/genai';

const OralTradition: React.FC = () => {
  const [connected, setConnected] = useState(false);
  const [status, setStatus] = useState('Disconnected');
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isSpeaking, setIsSpeaking] = useState(false);

  // References to keep track of audio context and session
  const sessionRef = useRef<any>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  const disconnect = () => {
    if (sessionRef.current) {
      // There isn't a close method on the promise wrapper directly exposed in all versions, 
      // but usually we just stop sending and close context.
      // In this specific SDK version, we can't easily "close" the session object returned by connect promise 
      // other than just stopping the streams.
    }
    inputContextRef.current?.close();
    outputContextRef.current?.close();
    setConnected(false);
    setStatus('Disconnected');
    setIsSpeaking(false);
  };

  const connect = async () => {
    setStatus('Connecting to Ancestral Spirits...');
    try {
      const ai = getLiveClient();

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      inputContextRef.current = inputCtx;
      outputContextRef.current = outputCtx;
      nextStartTimeRef.current = 0;

      const outputNode = outputCtx.createGain();
      outputNode.connect(outputCtx.destination);

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStatus('Connected. Speak freely.');
            setConnected(true);

            // Setup Audio Input Stream
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (msg: LiveServerMessage) => {
            const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;

            if (base64Audio) {
               setIsSpeaking(true);
               nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);

               const audioBuffer = await decodeAudioData(
                 // Using internal decode helper which assumes global atob
                 Uint8Array.from(atob(base64Audio), c => c.charCodeAt(0)), 
                 outputCtx,
                 24000,
                 1
               );

               const source = outputCtx.createBufferSource();
               source.buffer = audioBuffer;
               source.connect(outputNode);
               source.addEventListener('ended', () => {
                 sourcesRef.current.delete(source);
                 if (sourcesRef.current.size === 0) setIsSpeaking(false);
               });

               source.start(nextStartTimeRef.current);
               nextStartTimeRef.current += audioBuffer.duration;
               sourcesRef.current.add(source);
            }

            if (msg.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setIsSpeaking(false);
            }
          },
          onclose: () => {
            setStatus('Session Closed');
            setConnected(false);
          },
          onerror: (err) => {
            console.error(err);
            setStatus('Error occurred');
            setConnected(false);
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          systemInstruction: "You are a wise African elder and keeper of the oral traditions of the Swahili and Akan peoples. You speak with warmth, wisdom, and use proverbs where appropriate. You are teaching a younger generation about their heritage."
        }
      });

      sessionRef.current = sessionPromise;

    } catch (e) {
      console.error(e);
      setStatus('Failed to connect');
    }
  };

  useEffect(() => {
    return () => {
      disconnect();
    };
  }, []);

  return (
    <div className="max-w-4xl mx-auto p-6 flex flex-col items-center justify-center min-h-[60vh]">
      <div className={`w-48 h-48 rounded-full flex items-center justify-center mb-8 transition-all duration-1000 ${
        connected 
          ? isSpeaking 
            ? 'bg-amber-500 shadow-[0_0_50px_rgba(245,158,11,0.6)] scale-110' 
            : 'bg-amber-700 shadow-[0_0_30px_rgba(180,83,9,0.4)]'
          : 'bg-stone-300'
      }`}>
        <span className="text-6xl">{connected ? (isSpeaking ? '🗣️' : '👂') : '🦗'}</span>
      </div>

      <h2 className="text-4xl font-cinzel font-bold text-stone-800 mb-4">Oral Tradition</h2>
      <p className="text-stone-500 mb-8 text-center max-w-md">
        Connect with the AI Elder to discuss cultural history, ask for advice, or learn proverbs in a real-time conversation.
      </p>

      <div className="flex gap-4 items-center mb-6">
        <div className={`h-3 w-3 rounded-full ${connected ? 'bg-green-500' : 'bg-red-500'}`}></div>
        <span className="font-mono text-sm text-stone-600">{status}</span>
      </div>

      <button
        onClick={connected ? disconnect : connect}
        className={`px-8 py-4 rounded-full font-bold text-lg shadow-xl transition-all transform hover:scale-105 ${
          connected 
            ? 'bg-red-600 hover:bg-red-700 text-white' 
            : 'bg-stone-900 hover:bg-stone-800 text-amber-500'
        }`}
      >
        {connected ? 'End Conversation' : 'Begin Commune'}
      </button>
    </div>
  );
};

export default OralTradition;

import React, { useState } from 'react';
import { generateDesign, editDesign } from '../services/geminiService';

const Designer: React.FC = () => {
  const [mode, setMode] = useState<'create' | 'edit'>('create');
  const [prompt, setPrompt] = useState('');
  const [size, setSize] = useState<'1K' | '2K' | '4K'>('1K');
  const [generatedImages, setGeneratedImages] = useState<string[]>([]);
