import React, { useState, useRef } from 'react';
import { transcribeAudio } from '../services/geminiService';

const Transcription: React.FC = () => {
  const [recording, setRecording] = useState(false);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [audioBase64, setAudioBase64] = useState<string | null>(null);
  const [transcription, setTranscription] = useState('');
  const [loading, setLoading] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        const url = URL.createObjectURL(blob);
        setAudioUrl(url);

        const reader = new FileReader();
        reader.onloadend = () => {
           setAudioBase64(reader.result as string);
        };
        reader.readAsDataURL(blob);
      };

      mediaRecorder.start();
      setRecording(true);
    } catch (err) {
      console.error(err);
      alert("Microphone access denied.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.stop();
      setRecording(false);
    }
  };

  const handleTranscribe = async () => {
    if (!audioBase64) return;
    setLoading(true);
    try {
      // Extract base64 and mime
      const [mimePrefix, base64Data] = audioBase64.split(',');
      const mimeType = mimePrefix.match(/:(.*?);/)?.[1] || 'audio/webm';

      const result = await transcribeAudio(base64Data, mimeType);
      setTranscription(result || "Could not transcribe audio.");
    } catch (error) {
      console.error(error);
      setTranscription("Error during transcription.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto p-6">
      <h2 className="text-3xl font-bold text-amber-800 mb-2">Field Recorder</h2>
      <p className="text-stone-600 mb-8">Record elders or oral histories and transcribe them using AI.</p>

      <div className="bg-white p-8 rounded-xl shadow-lg border border-stone-200 flex flex-col items-center">
        <button
          onClick={recording ? stopRecording : startRecording}
          className={`w-20 h-20 rounded-full flex items-center justify-center text-3xl shadow-xl transition-all ${
            recording ? 'bg-red-500 animate-pulse text-white' : 'bg-stone-800 text-red-500 hover:bg-stone-700'
          }`}
        >
          {recording ? '⏹' : '⏺'}
        </button>
        <p className="mt-4 font-mono text-stone-500">
          {recording ? 'Recording in progress...' : 'Press to Record'}
        </p>

        {audioUrl && (
          <div className="w-full mt-8 bg-stone-50 p-4 rounded-lg">
            <audio src={audioUrl} controls className="w-full mb-4" />
            <button
              onClick={handleTranscribe}
              disabled={loading}
              className="w-full py-3 bg-amber-600 text-white font-bold rounded hover:bg-amber-700 disabled:opacity-50"
            >
              {loading ? 'Transcribing...' : 'Transcribe Recording'}
            </button>
          </div>
        )}
      </div>

      {transcription && (
        <div className="mt-8 bg-amber-50 p-6 rounded-xl border border-amber-200">
          <h3 className="font-bold text-amber-900 mb-2">Transcription</h3>
          <p className="text-stone-800 whitespace-pre-wrap">{transcription}</p>
        </div>
      )}
    </div>
  );
};

export default Transcription;

