import { GoogleGenAI, Modality, Type, FunctionDeclaration } from "@google/genai";
import { base64ToUint8Array, decodeAudioData } from "../utils/audioUtils";

const apiKey = process.env.API_KEY || '';

// For features requiring user-selected keys (Veo/Pro Image)
const getClientWithUserKey = async () => {
  // @ts-ignore
  if (window.aistudio && await window.aistudio.hasSelectedApiKey()) {
     // The SDK automatically picks up the key from the environment/context in this mode
     return new GoogleGenAI({ apiKey: 'ignored-in-this-context' }); 
  }
  // Fallback or error if not selected, but we usually check before calling this
  return new GoogleGenAI({ apiKey }); 
};

const getClient = () => new GoogleGenAI({ apiKey });

// 1. Analyze Artifact (Vision)
export const analyzeArtifact = async (base64Image: string, mimeType: string) => {
  const ai = getClient();
  const model = "gemini-3-pro-preview";

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { mimeType, data: base64Image } },
        { text: "Identify the symbols, patterns, or text in this image. If it is a Swahili Leso, translate the saying. If it is Adinkra, explain the symbol's meaning and cultural origin. Provide a detailed cultural interpretation." }
      ]
    }
  });
  return response.text;
};

// 2. Knowledge Base Search (Grounding)
export const searchCulturalKnowledge = async (query: string) => {
  const ai = getClient();
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: query,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  return {
    text: response.text,
    groundingMetadata: response.candidates?.[0]?.groundingMetadata
  };
};

// 3. Storytelling (Text Generation)
export const generateStory = async (topic: string) => {
  const ai = getClient();
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: `Create a short, culturally rich story or poem about: ${topic}. Incorporate elements of Swahili or Akan folklore.`,
    config: {
      maxOutputTokens: 800,
    }
  });
  return response.text;
};

// 4. TTS (Speech Generation)
export const generateSpeech = async (text: string): Promise<AudioBuffer> => {
  const ai = getClient();
  const model = "gemini-2.5-flash-preview-tts";

  const response = await ai.models.generateContent({
    model,
    contents: [{ parts: [{ text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' }, // Kore, Puck, Charon, Fenrir, Zephyr
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio generated");

  const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  return await decodeAudioData(
    base64ToUint8Array(base64Audio),
    outputAudioContext,
    24000,
    1
  );
};

// 5. Transcribe Audio
export const transcribeAudio = async (audioBase64: string, mimeType: string) => {
  const ai = getClient();
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { mimeType, data: audioBase64 } },
        { text: "Transcribe this audio. If it contains Swahili or other African languages, detect and translate the gist into English as well." }
      ]
    }
  });
  return response.text;
};

// 6. Image Generation (Pro Image - High Quality)
export const generateDesign = async (prompt: string, size: '1K' | '2K' | '4K') => {
  // Use client with user selected key
  const ai = await getClientWithUserKey();
  const model = "gemini-3-pro-image-preview";

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [{ text: `A traditional African textile design. ${prompt}` }]
    },
    config: {
      imageConfig: {
        imageSize: size,
        aspectRatio: "1:1"
      }
    }
  });

  // Extract images
  const images: string[] = [];
  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        images.push(`data:${part.inlineData.mimeType};base64,${part.inlineData.data}`);
      }
    }
  }
  return images;
};

// 7. Image Editing (Flash Image)
export const editDesign = async (imageBase64: string, mimeType: string, prompt: string) => {
  const ai = getClient();
  const model = "gemini-2.5-flash-image"; // Nano Banana

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { mimeType, data: imageBase64 } },
        { text: prompt }
      ]
    }
  });

  const images: string[] = [];
  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        images.push(`data:${part.inlineData.mimeType};base64,${part.inlineData.data}`);
      }
    }
  }
  return images;
};

// 8. Live API Connection helper
export const getLiveClient = () => {
    return new GoogleGenAI({ apiKey });
}

// 9. Generate Quiz Question (JSON Schema)
export const generateQuizQuestion = async () => {
  const ai = getClient();
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: "Generate a multiple-choice question about Adinkra symbols, Swahili proverbs, or African cultural history. Provide 4 options and the correct index.",
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          options: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          correctIndex: { type: Type.INTEGER },
          explanation: { type: Type.STRING }
        },
        required: ["question", "options", "correctIndex", "explanation"]
      }
    }
  });

  if (response.text) {
    return JSON.parse(response.text);
  }
  throw new Error("Failed to generate quiz");
};

// 10. Moderate & Curate Content
export const moderateContent = async (text: string, imageBase64?: string) => {
  const ai = getClient();
  const model = "gemini-3-flash-preview";

  const parts: any[] = [{ text: `You are a cultural curator. Review the following submission for an African heritage platform. 
  1. Check for offensive or culturally insensitive content.
  2. If safe, provide a short, encouraging "Curator's Note" adding historical context or appreciation. 
  3. If unsafe, output ONLY "UNSAFE".

  Submission Text: ${text}` }];

  if (imageBase64) {
    const [mimePrefix, data] = imageBase64.split(',');
    const mimeType = mimePrefix.match(/:(.*?);/)?.[1] || 'image/jpeg';
    parts.push({ inlineData: { mimeType, data } });
  }

  const response = await ai.models.generateContent({
    model,
    contents: { parts }
  });

  return response.text?.trim() || "UNSAFE";
};

