import React, { useState, useEffect } from 'react';
import { generateQuizQuestion } from '../services/geminiService';
import { QuizQuestion } from '../types';

const WisdomQuest: React.FC = () => {
  const [currentQuestion, setCurrentQuestion] = useState<QuizQuestion | null>(null);
  const [score, setScore] = useState(0);
  const [loading, setLoading] = useState(false);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);
  const [streak, setStreak] = useState(0);

  const leaderboard = [
    { name: 'Nia', score: 450 },
    { name: 'Kwesi', score: 320 },
    { name: 'You', score: score },
    { name: 'Amani', score: 180 },
  ].sort((a, b) => b.score - a.score);

  const fetchQuestion = async () => {
    setLoading(true);
    setSelectedOption(null);
    setIsCorrect(null);
    try {
      const question = await generateQuizQuestion();
      setCurrentQuestion(question);
    } catch (error) {
      console.error(error);
      // Fallback question
      setCurrentQuestion({
        question: "What does the 'Sankofa' symbol represent?",
        options: ["War", "Learning from the past", "Agriculture", "Music"],
        correctIndex: 1,
        explanation: "Sankofa means 'Go back and fetch it', symbolizing the importance of learning from the past to build the future."
      });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchQuestion();
  }, []);

  const handleAnswer = (index: number) => {
    if (selectedOption !== null || !currentQuestion) return;

    setSelectedOption(index);
    const correct = index === currentQuestion.correctIndex;
    setIsCorrect(correct);

    if (correct) {
      setScore(s => s + 10 + (streak * 2));
      setStreak(s => s + 1);
    } else {
      setStreak(0);
    }
  };

  return (
    <div className="max-w-6xl mx-auto p-6 flex flex-col md:flex-row gap-8">
      {/* Quiz Area */}
      <div className="flex-1">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-3xl font-bold text-amber-800">Wisdom Quest</h2>
          <div className="flex items-center gap-4">
            <div className="bg-amber-100 text-amber-800 px-4 py-2 rounded-full font-bold">
              🔥 Streak: {streak}
            </div>
            <div className="bg-stone-800 text-white px-4 py-2 rounded-full font-bold">
              Score: {score}
            </div>
          </div>
        </div>

        <div className="bg-white p-8 rounded-2xl shadow-xl border-2 border-stone-200 min-h-[400px] flex flex-col justify-center relative overflow-hidden">
          {loading ? (
            <div className="text-center animate-pulse">
              <div className="text-6xl mb-4">🗿</div>
              <p className="text-stone-500 font-cinzel text-xl">Consulting the Oracle...</p>
            </div>
          ) : currentQuestion ? (
            <>
              <h3 className="text-2xl font-bold text-stone-800 mb-8 leading-relaxed">
                {currentQuestion.question}
              </h3>

              <div className="grid grid-cols-1 gap-4">
                {currentQuestion.options.map((option, idx) => (
                  <button
                    key={idx}
                    onClick={() => handleAnswer(idx)}
                    disabled={selectedOption !== null}
                    className={`p-4 rounded-xl text-left text-lg font-medium transition-all transform hover:scale-[1.01] ${
                      selectedOption === null 
                        ? 'bg-stone-100 hover:bg-stone-200 text-stone-700' 
                        : idx === currentQuestion.correctIndex
                          ? 'bg-green-100 border-2 border-green-500 text-green-800'
                          : selectedOption === idx
                            ? 'bg-red-100 border-2 border-red-500 text-red-800'
                            : 'opacity-50 bg-stone-100'
                    }`}
                  >
                    <span className="inline-block w-8 font-bold opacity-50">{String.fromCharCode(65 + idx)}.</span>
                    {option}
                  </button>
                ))}
              </div>

              {selectedOption !== null && (
                <div className="mt-8 p-6 bg-amber-50 rounded-xl border border-amber-200 animate-fade-in">
                  <p className={`font-bold mb-2 ${isCorrect ? 'text-green-600' : 'text-stone-600'}`}>
                    {isCorrect ? 'Correct! 🎉' : 'Lesson Learned 📚'}
                  </p>
                  <p className="text-stone-800 italic mb-4">{currentQuestion.explanation}</p>
                  <button
                    onClick={fetchQuestion}
                    className="bg-stone-900 text-white px-6 py-2 rounded-lg font-bold hover:bg-stone-700 transition-colors"
                  >
                    Next Challenge →
                  </button>
                </div>
              )}
            </>
          ) : (
            <div className="text-center text-red-500">Failed to load question.</div>
          )}
        </div>
      </div>

      {/* Sidebar / Leaderboard */}
      <div className="w-full md:w-80">
        <div className="bg-stone-900 text-amber-50 p-6 rounded-xl shadow-lg sticky top-6">
          <h3 className="text-xl font-cinzel font-bold mb-4 border-b border-stone-700 pb-2">
            Top Scholars
          </h3>
          <ul className="space-y-4">
            {leaderboard.map((entry, index) => (
              <li key={index} className={`flex justify-between items-center p-3 rounded-lg ${entry.name === 'You' ? 'bg-amber-900 border border-amber-600' : 'bg-stone-800'}`}>
                <div className="flex items-center gap-3">
                  <span className={`font-bold text-lg w-6 ${index === 0 ? 'text-yellow-400' : index === 1 ? 'text-gray-400' : index === 2 ? 'text-amber-700' : 'text-stone-500'}`}>
                    {index + 1}
                  </span>
                  <span className="font-medium">{entry.name}</span>
                </div>
                <span className="font-mono text-amber-400 font-bold">{entry.score}</span>
              </li>
            ))}
          </ul>

          <div className="mt-8 bg-stone-800 p-4 rounded-lg">
            <h4 className="text-sm font-bold text-stone-400 uppercase mb-2">Your Rank</h4>
            <p className="text-xs text-stone-500">
              Keep learning to climb the ranks and earn the title of "Village Sage".
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

