import React, { useState } from 'react';
import { analyzeArtifact } from '../services/geminiService';

const ImageAnalyzer: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<string>('');
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setAnalysis('');
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAnalyze = async () => {
    if (!image) return;
    setLoading(true);
    try {
      // Extract base64 and mime type
      const [mimePrefix, base64Data] = image.split(',');
      const mimeType = mimePrefix.match(/:(.*?);/)?.[1] || 'image/jpeg';

      const result = await analyzeArtifact(base64Data, mimeType);
      setAnalysis(result || "No analysis could be generated.");
    } catch (error) {
      console.error(error);
      setAnalysis("Error analyzing the artifact. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto p-6">
      <h2 className="text-3xl font-bold text-amber-900 mb-2 font-cinzel text-shadow">Artifact Analyzer</h2>
      <p className="text-stone-800 font-medium mb-8">Upload an image of a Leso, Adinkra cloth, or artifact to decode its meaning.</p>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="glass-panel p-6 rounded-2xl shadow-xl">
          <label className="block w-full h-80 border-2 border-dashed border-stone-400/50 rounded-xl flex flex-col items-center justify-center cursor-pointer hover:bg-white/30 hover:border-amber-500 transition-all bg-white/10">
            {image ? (
              <img src={image} alt="Artifact" className="h-full w-full object-contain rounded-lg" />
            ) : (
              <div className="text-center p-4">
                <span className="text-5xl block mb-4">📸</span>
                <span className="text-stone-600 font-bold text-lg">Click to upload image</span>
              </div>
            )}
            <input type="file" className="hidden" accept="image/*" onChange={handleFileChange} />
          </label>

          <button
            onClick={handleAnalyze}
            disabled={!image || loading}
            className={`w-full mt-6 py-4 rounded-lg font-bold text-white transition-all shadow-lg transform hover:scale-[1.02] ${
              !image || loading
                ? 'bg-stone-500 cursor-not-allowed opacity-70'
                : 'bg-amber-700 hover:bg-amber-800'
            }`}
          >
            {loading ? 'Consulting the Ancestors...' : 'Analyze Artifact'}
          </button>
        </div>

        <div className="glass-card p-8 rounded-2xl shadow-inner h-full overflow-y-auto min-h-[400px]">
          <h3 className="text-xl font-bold text-amber-900 mb-4 border-b border-stone-300/50 pb-2">Wisdom Revealed</h3>
          {analysis ? (
            <div className="prose prose-stone text-stone-900 whitespace-pre-wrap font-medium">
              {analysis}
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-stone-500 opacity-60">
                <span className="text-4xl mb-2">👁️</span>
                <p className="italic">The interpretation will appear here.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ImageAnalyzer;

import React, { useState } from 'react';
import { searchCulturalKnowledge } from '../services/geminiService';

const KnowledgeBase: React.FC = () => {
  const [query, setQuery] = useState('');
  const [result, setResult] = useState<{ text: string; groundingMetadata?: any } | null>(null);
  const [loading, setLoading] = useState(false);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;
    setLoading(true);
    try {
      const data = await searchCulturalKnowledge(query);
      setResult(data);
    } catch (error) {
      console.error(error);
      setResult({ text: "Could not retrieve knowledge at this time." });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <h2 className="text-3xl font-bold text-amber-900 mb-6 font-cinzel text-shadow">Ancestral Knowledge Base</h2>

      <form onSubmit={handleSearch} className="mb-10">
        <div className="relative group">
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            className="w-full p-5 pl-14 rounded-full glass-panel border border-white/50 shadow-xl focus:outline-none focus:ring-4 focus:ring-amber-500/30 text-lg placeholder-stone-500 text-stone-900 transition-all"
            placeholder="Search for proverbs, symbols, or history..."
          />
          <span className="absolute left-6 top-1/2 transform -translate-y-1/2 text-2xl opacity-70">🔎</span>
          <button
            type="submit"
            className="absolute right-3 top-2 bottom-2 px-8 bg-stone-900 text-white rounded-full font-bold hover:bg-stone-800 transition-colors shadow-lg"
          >
            {loading ? 'Searching...' : 'Search'}
          </button>
        </div>
      </form>

      {result && (
        <div className="glass-panel p-10 rounded-2xl shadow-2xl animate-fade-in">
          <div className="prose prose-lg text-stone-900 mb-8 whitespace-pre-wrap leading-relaxed">
            {result.text}
          </div>

          {/* Rendering Grounding Sources */}
          {result.groundingMetadata?.groundingChunks && (
            <div className="mt-8 border-t border-stone-300/50 pt-6">
              <h4 className="text-xs font-bold text-stone-600 uppercase tracking-widest mb-4">Sources & References</h4>
              <ul className="space-y-3">
                {result.groundingMetadata.groundingChunks.map((chunk: any, index: number) => {
                  if (chunk.web?.uri) {
                    return (
                      <li key={index} className="flex items-center gap-3 text-sm group">
                        <span className="text-stone-400 group-hover:text-amber-600 transition-colors">🔗</span>
                        <a 
                          href={chunk.web.uri} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="text-stone-700 font-bold hover:text-amber-700 hover:underline truncate max-w-lg block transition-colors"
                        >
                          {chunk.web.title || chunk.web.uri}
                        </a>
                      </li>
                    );
                  }
                  return null;
                })}
              </ul>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default KnowledgeBase;

