```typescript
import { GoogleGenAI, Modality, Type, FunctionDeclaration, Part, Content } from "@google/genai";
import { base64ToUint8Array, decodeAudioData } from "../utils/audioUtils";

const apiKey = process.env.API_KEY || '';

const genAI = new GoogleGenAI(apiKey);

export interface CommunityPost {
  id: string;
  author: string;
  title: string;
  content: string;
  image?: string;
  likes: number;
  aiCuratorNote?: string;
  timestamp: Date;
}

export async function generateContent(
  textModel: string,
  systemInstructions: string,
  userPrompt: string,
  modality: Modality = Modality.TEXT,
  image?: string,
): Promise<string | AudioBuffer> {
  try {
    const model = genAI.getGenerativeModel({ model: textModel });
    const parts: Part[] = [
      { text: systemInstructions },
      { text: userPrompt },
    ];
    if (image) {
      parts.push({
        inlineData: {
          mimeType: "image/jpeg", // or "image/png" depending on your image type
          data: image,
        },
      });
    }

    const result = await model.generateContent({ parts });
    const response = result.response;
    if (response) {
      if (modality === Modality.AUDIO) {
        const audioBuffer = base64ToUint8Array(response.text());
        return audioBuffer;
      }
      return response.text();
    } else {
      throw new Error("No response from the model.");
    }
  } catch (error) {
    console.error("Error generating content:", error);
    throw error; // Re-throw to be handled upstream
  }
}

export async function generateStory(topic: string): Promise<string> {
  const systemInstructions = `You are a helpful storyteller. Write a children's story, suitable for an oral storytelling tradition.`;
  const userPrompt = `Write a short story about ${topic}.`;
  return generateContent("gemini-3-pro-preview", systemInstructions, userPrompt) as Promise<string>;
}

export async function generateSpeech(text: string): Promise<AudioBuffer> {
  const systemInstructions = `You are a helpful text-to-speech engine. Generate speech from the text provided. Respond in base64.`;
  const userPrompt = text;
  const audioData = await generateContent("gemini-2.5-flash-preview-tts", systemInstructions, userPrompt, Modality.AUDIO) as Uint8Array;
  const audioContext = new (window.AudioContext || window.webkitAudioContext)();
  return new Promise((resolve, reject) => {
    audioContext.decodeAudioData(audioData.buffer, (buffer) => {
      resolve(buffer);
    }, (error) => {
      console.error("Error decoding audio data:", error);
      reject(error);
    });
  });
}

export async function moderateContent(text: string, image?: string): Promise<string> {
  const systemInstructions = `You are a content moderation assistant. Determine if the text is safe and appropriate for all audiences. Respond with a curator note if unsafe, or just "SAFE" if safe.`;
  let userPrompt = text;
  if (image) {
    userPrompt = `Text: ${text}\n Image: ${image}`;
  }
  try {
    const moderatorResult = await generateContent("gemini-3-flash-preview", systemInstructions, userPrompt);
    if (moderatorResult.toUpperCase().includes("SAFE")) {
      return "SAFE";
    }
    return moderatorResult;
  } catch (error) {
    console.error("Error moderating content:", error);
    return "UNSAFE";
  }
}
```



