const apiKey = process.env.API_KEY || '';

// For features requiring user-selected keys (Veo/Pro Image)
const getClientWithUserKey = async () => {
  // @ts-ignore
  if (window.aistudio && await window.aistudio.hasSelectedApiKey()) {
     // The SDK automatically picks up the key from the environment/context in this mode
     return new GoogleGenAI({ apiKey: 'ignored-in-this-context' }); 
  }
  // Fallback or error if not selected, but we usually check before calling this
  return new GoogleGenAI({ apiKey }); 
};

const getClient = () => new GoogleGenAI({ apiKey });

// Helper: Retry logic for 429 Errors
const withRetry = async <T>(operation: () => Promise<T>, retries = 4, delay = 2000): Promise<T> => {
  try {
    return await operation();
  } catch (error: any) {
    const isQuotaError = error.status === 429 || error.code === 429 || error.message?.includes('429') || error.message?.includes('Quota exceeded') || error.message?.includes('RESOURCE_EXHAUSTED');

    if (isQuotaError && retries > 0) {
      console.warn(`Quota exceeded. Retrying in ${delay}ms...`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(operation, retries - 1, delay * 2);
    }

    if (isQuotaError) {
      throw new Error("AI Quota exceeded. Please try again later.");
    }
    throw error;
  }
};

