export const analyzeArtifact = async (base64Image: string, mimeType: string, mode: 'fast' | 'deep' = 'deep') => {
  return withRetry(async () => {
    const ai = getClient();
    // Use Flash for speed, Pro for deep reasoning. Both use Search for accuracy.
